INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(12, 1, '13', '주식 시장 구조', '문서에서 코스피(KOSPI) 시장의 퀀트 분석 포인트로 제시된 것은?', '변동성, 거래대금, 테마 민감도', '시가총액, 외국인 수급, 경기 민감도', '금리 민감도, 성장률, 밸류에이션', '거래량, 괴리율, 추적오차', 2, '문서 주식 시장 구조 표에서 코스피는 대형·우량 기업 중심 시장으로 퀀트 분석 포인트는 시가총액, 외국인 수급, 경기 민감도라고 설명합니다.'),
(12, 2, '13', '주식 시장 구조', '문서에서 나스닥(NASDAQ) 시장의 특징으로 제시된 것은?', '대형·우량 기업 중심으로 경기 민감도가 핵심 분석 포인트', '성장주·중소형주 중심으로 변동성과 테마 민감도가 높음', '기술주·성장주 비중이 높으며 금리 민감도와 성장률이 핵심 분석 포인트', '코스닥보다 규모가 작으며 초기 스타트업 중심', 3, '문서 주식 시장 구조 표에서 나스닥은 기술주·성장주 비중이 높고, 퀀트 분석 포인트는 금리 민감도, 성장률, 밸류에이션이라고 설명합니다.'),
(12, 3, '13', '주식 기본 개념', '문서에서 EPS(주당순이익)의 계산식으로 제시된 것은?', '주가 ÷ 발행주식수', '순이익 ÷ 발행주식수', '순자산 ÷ 발행주식수', '주당배당금 ÷ 주가', 2, '문서 주식 기본 개념 표에서 EPS는 순이익 ÷ 발행주식수로 계산하며, 주식 1주가 벌어들인 이익을 나타낸다고 설명합니다.'),
(12, 4, '13', '주식 기본 개념', '문서에서 PER(주가수익비율)의 해석으로 제시된 것은?', '1주당 장부가치 대비 시장 가격 수준', '이익 대비 주가 수준', '현금 배당 매력', '시장이 평가한 기업 전체 가치', 2, '문서 주식 기본 개념 표에서 PER은 주가 ÷ EPS로 계산하며 이익 대비 주가 수준을 나타낸다고 설명합니다.'),
(12, 5, '13', '순자산·BPS·PBR', '문서에서 BPS(주당순자산)의 계산식으로 제시된 것은?', '순이익 ÷ 발행주식수', '주가 ÷ 순자산', '순자산 ÷ 발행주식수', '자산 ÷ 부채', 3, '문서 순자산·BPS·PBR 표에서 BPS(주당순자산)는 순자산 ÷ 발행주식수로 계산하며 주식 1주당 장부가치를 나타낸다고 설명합니다.'),
(12, 6, '13', '순자산·BPS·PBR', '문서에서 PBR이 1배 미만일 때의 해석으로 제시된 것은?', '수익 대비 고평가 가능성이 있어 주의가 필요하다', '장부가치 대비 저평가로 해석되기도 하지만 업황·수익성 악화 반영일 수도 있어 단독 판단은 위험하다', '기업의 배당 수익률이 낮음을 의미한다', '이익 창출 능력이 우수하여 성장 프리미엄이 붙은 것이다', 2, '문서 순자산·BPS·PBR 섹션에서 PBR이 1배보다 낮으면 장부가치 대비 저평가로 해석되기도 하지만, 업황·수익성 악화가 반영된 결과일 수도 있어 단독 판단은 위험하다고 설명합니다.'),
(12, 7, '13', '호가 스프레드', '문서에서 호가 스프레드(Bid-Ask Spread)가 좁을수록 나타나는 효과로 제시된 것은?', '즉시 체결 가능성이 낮아져 유동성 위험이 증가한다', '거래비용·슬리피지 부담이 줄어든다', '매도호가가 매수호가보다 항상 낮아진다', '괴리율이 커져 ETF 투자 리스크가 증가한다', 2, '문서 주식 거래 기본 표에서 호가 스프레드는 좁을수록 거래비용·슬리피지 부담이 줄어든다고 설명합니다.'),
(12, 8, '13', '펀드 클래스', '문서에서 A클래스 펀드가 유리한 투자 기간으로 제시된 것은?', '1년 미만 단기 투자', '2년 이상 장기 보유', '6개월 이내 초단기 투자', '3개월 단위 정기적립 투자', 2, '문서 펀드 클래스 표에서 A클래스는 선취수수료가 있고 연간 보수가 낮아 2년 이상 장기 보유 시 유리하다고 설명합니다.'),
(12, 9, '13', '펀드 클래스', '문서에서 C클래스 펀드의 수수료 구조로 제시된 것은?', '선취수수료 O + 연간 보수 낮음', '선취수수료 X + 연간 보수 높음', '선취수수료 O + 연간 보수 높음', '선취수수료 X + 연간 보수 낮음', 2, '문서 펀드 클래스 표에서 C클래스는 선취수수료가 없고 연간 보수가 높으며, 단기 보유(1년 미만) 시 유리하다고 설명합니다.'),
(12, 10, '13', '펀드 클래스', '문서에서 펀드 P클래스(또는 P2)의 특징으로 제시된 것은?', '기관투자자 전용으로 대규모 투자 시 매우 낮은 보수 적용', '연금저축계좌에서만 매수 가능하며 세제혜택과 연계', '펀드슈퍼마켓에서만 판매되며 낮은 보수로 비용 절약 가능', '증권사 랩어카운트에서 자동 편입되는 전용 클래스', 2, '문서 펀드 클래스 표에서 P클래스(또는 P2)는 연금저축 전용으로 연금저축계좌에서만 매수 가능하며 세제혜택과 연계된다고 설명합니다.'),
(12, 11, '13', 'ETF 기본', '문서에서 ETF(Exchange Traded Fund)의 한 줄 요약으로 제시된 것은?', '여럿이 돈을 모아 전문가에게 대신 투자하게 맡기는 것', '주식처럼 실시간으로 사고팔 수 있는 펀드', '만기 시 원금과 이자를 지급하는 채권형 상품', '장외 거래소에서 거래되는 비상장 수익증권', 2, '문서 ETF란 초등학생도 이해하는 설명 섹션에서 ETF의 한 줄 요약은 "주식처럼 실시간으로 사고팔 수 있는 펀드"라고 제시합니다.'),
(12, 12, '13', 'ETF NAV', '문서에서 NAV(순자산가치)의 계산식으로 제시된 것은?', '(총자산 - 부채) ÷ 발행주식수', '시장가격 ÷ 발행주식수', '(총자산 + 부채) ÷ 발행주식수', '(시장가격 - NAV) ÷ NAV × 100', 1, '문서 NAV·괴리율·추적오차 표에서 NAV(순자산가치)는 (총자산 - 부채) ÷ 발행주식수로 계산하며, ETF가 보유한 자산의 실제 주당 가치를 나타낸다고 설명합니다.'),
(12, 13, '13', 'ETF 괴리율', '문서에서 ETF 괴리율(Gap Rate)의 계산식으로 제시된 것은?', 'NAV ÷ 시장가격 × 100', '(시장가격 - NAV) ÷ NAV × 100', '(NAV - 시장가격) ÷ 시장가격', 'std(ETF 수익률 - 지수 수익률)', 2, '문서 NAV·괴리율·추적오차 표에서 괴리율은 (시장가격 - NAV) ÷ NAV × 100으로 계산하며, 양수이면 프리미엄, 음수이면 디스카운트 상태를 의미한다고 설명합니다.'),
(12, 14, '13', 'ETF 괴리율', '문서에서 정상 범위의 ETF 괴리율 기준으로 제시된 것은?', '±0.1% 이내', '±0.5% 이내', '±1% 이내', '±3% 이내', 3, '문서 NAV·괴리율·추적오차 섹션에서 ±1% 이내의 괴리율이 정상 범위이며, 유동성이 낮은 ETF는 괴리율이 커질 수 있어 주의가 필요하다고 설명합니다.'),
(12, 15, '13', 'ETF LP·AP', '문서에서 ETF 시장의 AP(지정참가회사)의 역할로 제시된 것은?', '양방향 호가(매수/매도)를 제시해 스프레드를 완화한다', 'ETF 설정·환매를 통해 시장가격과 NAV 괴리를 축소한다', '운용 전략을 직접 결정하고 포트폴리오를 관리한다', '기초자산을 스왑 계약으로 교환하여 지수 수익률을 복제한다', 2, '문서 ETF LP·AP 역할 표에서 AP(지정참가회사)는 ETF 설정·환매를 통해 시장가격과 NAV 괴리를 축소하는 역할을 한다고 설명합니다.'),
(12, 16, '13', 'ETF 선택 조건', '문서에서 ETF 선택 시 함께 확인해야 할 4가지 항목으로 제시된 것은?', '수익률, 시가총액, 분배금, 설정일', '수익률, 괴리율, 추적오차, 펀드보수(TER)', '수익률, 거래량, 환헤지 여부, 운용사 신용등급', '수익률, 레버리지 배수, 상장국가, 기초지수', 2, '문서 ETF 선택 조건 표에서 ETF를 고를 때는 수익률, 괴리율, 추적오차, 펀드보수(TER/총보수) 4가지를 함께 확인해야 한다고 설명합니다.'),
(12, 17, '13', 'ETF 종류', '문서에서 레버리지 ETF(2×)의 장기 보유 시 위험으로 제시된 것은?', '괴리율이 지속적으로 증가해 NAV와 시장가격 차이가 벌어진다', '추적오차가 커져 지수를 2배 이상 초과하는 손실이 발생한다', '변동성 끌림(Volatility Drag)으로 복리 손실이 발생한다', '펀드보수(TER)가 매일 2배씩 차감되어 원금이 급격히 줄어든다', 3, '문서 레버리지·인버스 ETF 표에서 레버리지·인버스 ETF는 일일 수익률 기준으로 운용되며, 횡보장이 지속되면 변동성 끌림(Volatility Drag) 현상으로 복리 손실이 발생한다고 설명합니다.'),
(12, 18, '13', 'ETF 종류', '문서에서 합성 복제 ETF의 단점으로 제시된 것은?', '투명성이 낮아 구성 종목 파악이 어렵다', '스왑 상대방 부도 위험이 존재한다', '실물 자산을 직접 보유해 거래 비용이 높다', '장중 실시간 거래가 불가능하다', 2, '문서 실물 복제 vs 합성 복제 표에서 합성 복제 ETF는 스왑 계약으로 지수 수익률을 교환하는 방식으로 접근 어려운 자산도 추종할 수 있지만, 스왑 상대방 부도 위험이 있다고 설명합니다.'),
(12, 19, '13', 'ETF 환헤지', '문서에서 달러 강세 국면에서 유리한 ETF 유형으로 제시된 것은?', '환헤지(H) ETF가 유리하다', '환노출 ETF가 유리하다', '레버리지 ETF가 유리하다', '인버스 ETF가 유리하다', 2, '문서 환헤지 여부 섹션에서 달러 강세 국면에서는 환노출 ETF가 유리하고, 달러 약세 국면에서는 환헤지 ETF가 유리하다고 설명합니다.'),
(12, 20, '13', 'ETF 운용 전략', '문서에서 패시브(Passive) ETF의 장점으로 제시된 것은?', '운용자 판단이 반영되어 시장 상황에 능동적으로 대응한다', '낮은 비용과 높은 투명성이 장점이다', '가치·모멘텀 등 특정 요인에 집중하여 초과수익을 추구한다', '단기 방향성 거래로 큰 수익이 가능하다', 2, '문서 ETF 운용 전략 표에서 패시브 ETF는 지수를 추종하며 낮은 비용과 높은 투명성이 장점이지만, 시장 하락을 그대로 반영하는 단점이 있다고 설명합니다.'),
(12, 21, '13', 'ETF 운용 전략', '문서에서 스마트베타/팩터 ETF의 TER(총보수) 수준으로 제시된 것은?', '0.05~0.3%로 낮은 수준', '0.5~1.0%로 높은 수준', '0.2~0.5%로 중간 수준', '1.0% 이상으로 매우 높은 수준', 3, '문서 ETF 운용 방식 표에서 스마트베타/팩터 ETF는 가치·모멘텀 등 특정 요인에 집중하며 TER이 중간(0.2~0.5%) 수준이라고 설명합니다.'),
(12, 22, '13', 'ETF vs 일반펀드', '문서에서 일반펀드(공모펀드)와 ETF의 체결 시점 차이로 제시된 것은?', '일반펀드는 주문 즉시 체결되고, ETF는 기준가로 일괄 처리된다', '일반펀드는 기준가로 일괄 처리되고, ETF는 주문 즉시 체결 가능하다', '일반펀드와 ETF 모두 장 마감 후 기준가로 처리된다', '일반펀드와 ETF 모두 장중 실시간으로 체결된다', 2, '문서 일반펀드 vs ETF 표에서 일반펀드는 기준가로 일괄 처리되고, ETF는 주문 즉시 체결 가능하여 장중 변동 대응이 가능하다고 설명합니다.'),
(12, 23, '13', 'ETF vs 일반펀드', '문서에서 ETF가 일반펀드보다 유리한 경우로 제시된 것은?', '퇴직연금/연금저축 계좌에서 장기 자동적립을 주로 할 때', '운용사의 액티브 판단(종목선택)을 그대로 맡기고 싶을 때', '지수 추종 + 낮은 비용 + 높은 투명성을 우선할 때', '선취수수료를 피하고 연간 보수를 통일하고 싶을 때', 3, '문서 ETF가 유리한 경우 섹션에서 장중 분할매수·분할매도, 지수 추종 + 낮은 비용 + 높은 투명성을 우선할 때 ETF가 유리하다고 설명합니다.'),
(12, 24, '13', 'Gross vs Net', '문서에서 Net(넷) 수익률의 의미로 제시된 것은?', '비용·세금 등을 빼기 전 수치(총액)', '비용·세금 등을 뺀 뒤 실제 남는 수치(순액)', '지수 자체 상승률을 확인하기 위한 원자료 수치', '레버리지 ETF의 일일 수익률 배수를 나타내는 수치', 2, '문서 Net vs Gross 섹션에서 Net(넷)은 비용·세금 등을 뺀 뒤 실제 남는 수치(순액)로 투자자가 체감하는 실제 계좌 성과에 더 가깝다고 설명합니다.'),
(12, 25, '13', '시가총액', '문서에서 시가총액(Market Capitalization)의 계산식으로 제시된 것은?', '순이익 ÷ 발행주식수', '주가 ÷ EPS', '주가 × 발행주식수', '순자산 ÷ 발행주식수', 3, '문서 주식 기본 개념 표에서 시가총액은 주가 × 발행주식수로 계산하며, 시장이 평가한 기업 전체 가치를 나타낸다고 설명합니다.'),
(12, 26, '13', '배당수익률', '문서에서 배당수익률(Dividend Yield)의 계산식으로 제시된 것은?', '순이익 ÷ 발행주식수', '주가 ÷ EPS', '주당배당금 ÷ 주가', '배당총액 ÷ 당기순이익', 3, '문서 주식 기본 개념 표에서 배당수익률은 주당배당금 ÷ 주가로 계산하며, 현금 배당 매력을 나타낸다고 설명합니다.'),
(12, 27, '13', 'ETF 비용', '문서에서 거래 수수료와 펀드보수(TER)의 차이로 제시된 것은?', '거래 수수료와 펀드보수 모두 매수/매도 시마다 증권사에 납부한다', '거래 수수료는 보유 기간 동안 매일 반영되고, 펀드보수는 거래 시마다 한 번 납부한다', '거래 수수료는 매수/매도 시마다 증권사에 납부하고, 펀드보수는 보유 기간 동안 운용사 등에 계속 반영된다', '거래 수수료는 운용사가, 펀드보수는 증권사가 수취한다', 3, '문서 거래 수수료 vs 펀드보수(TER) 표에서 주식거래 수수료는 매수/매도 주문 체결 시마다 증권사에 내는 비용이고, 펀드보수는 ETF를 보유하는 기간 동안 매일/연간 누적되어 운용사 등에게 귀속되는 비용이라고 설명합니다.'),
(12, 28, '13', 'ETF 브랜드', '문서에서 미국 대표 ETF 브랜드로 제시된 것은?', 'KODEX, TIGER, KINDEX, KOSEF', 'iShares, Vanguard, SPDR, Invesco', 'SOL, HANARO, ACE, RISE', 'KBSTAR, VanEck, Global X, KOSEF', 2, '문서 ETF 브랜드 표에서 미국 대표 ETF 브랜드로 iShares, Vanguard, SPDR, Invesco, Schwab, WisdomTree, VanEck, Global X가 제시됩니다.'),
(12, 29, '13', '자격시험 문항 구성', '문서에서 투자자산운용사 2과목 중 문항 수가 가장 많은 세부과목으로 제시된 것은?', '대안투자운용/투자전략 (5문항)', '해외증권투자운용/투자전략 (5문항)', '투자분석기법 (12문항)', '리스크관리 (8문항)', 3, '문서 투자자산운용사(2과목) 문항 구성 표에서 투자분석기법이 12문항으로 가장 많은 문항을 차지한다고 설명합니다.'),
(12, 30, '13', '자격시험 문항 구성', '문서에서 1과목(증권분석기초) 총 문항 수와 과락 기준으로 제시된 것은?', '총 30문항, 12문항 미만 과락', '총 25문항, 10문항 미만 과락', '총 50문항, 20문항 미만 과락', '총 20문항, 8문항 미만 과락', 2, '문서 1과목(증권분석기초) 문항 구성 섹션에서 총 문항 수는 25문항이며 10문항 미만 정답 시 과락이라고 설명합니다.');
